+    padding: 8px;
+  }
+
+  .log-time {
+    font-size: 10px;
+  }
+
+  .log-level {
+    font-size: 9px;
+  }
+
+  .log-subsystem {
+    font-size: 11px;
+  }
+
+  .log-message {
+    font-size: 12px;
+  }
+
+  /* Hide docs link on mobile - saves space */
+  .docs-link {
+    display: none;
+  }
+
+  /* List items */
+  .list-item {
+    padding: 10px;
+    border-radius: 10px;
+  }
+
+  .list-title {
+    font-size: 14px;
+  }
+
+  .list-sub {
+    font-size: 11px;
+  }
+
