+  .code-block {
+    padding: 8px;
+    border-radius: 10px;
+    font-size: 11px;
+  }
+
+  /* Theme toggle smaller */
+  .theme-toggle {
+    --theme-item: 24px;
+    --theme-gap: 4px;
+    --theme-pad: 4px;
+  }
+
+  .theme-icon {
+    width: 14px;
+    height: 14px;
+  }
+}
